// Gatekeeper: only our UI (which knows the shared secret) may trigger a send.
const secret = $('Config').first().json.reply_secret;
if (!secret || secret.startsWith('<<')) {
  throw new Error('Config: reply_secret is not set');
}
const item = $input.first();
const headers = item.json.headers || {};
const provided = headers['x-inbox-secret'];
if (!provided || provided !== secret) {
  throw new Error('401 Unauthorized: bad or missing x-inbox-secret');
}

const body = item.json.body || {};
const conversationId = body.conversation_id;
const text = (body.text || '').trim();
if (!conversationId) throw new Error('conversation_id is required');
if (!text) throw new Error('text is required');

return [{ json: { conversation_id: conversationId, text } }];

// Derive from/to, guard against reply loops, assemble the Telnyx payload.
const rows = $input.first().json;
const conv = Array.isArray(rows) ? rows[0] : rows;
if (!conv || !conv.telnyx_number || !conv.contact_number) {
  throw new Error('Conversation not found');
}

const from = conv.telnyx_number;   // our Telnyx number
const to = conv.contact_number;    // the person we are replying to
if (from === to) {
  throw new Error('Loop guard: refusing to text our own number');
}

const text = $('Validate').first().json.text;
const conversationId = $('Validate').first().json.conversation_id;
const mpid = $('Config').first().json.messaging_profile_id;

const payload = { from, to, text };
if (mpid) payload.messaging_profile_id = mpid;

return [{ json: { conversation_id: conversationId, from, to, text, telnyx_payload: payload } }];
